ber IS NULL;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(10,'How many events does each member have?','student_club','MEDIUM','SELECT m.member_id, COUNT(a.link_to_event) AS total_events\nFROM member m\nJOIN attendance a ON a.link_to_member = m.member_id\nGROUP BY m.member_id;',0,'Used wrong column name (a.event_id). Correct column is link_to_event.','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(11,'Which events have more than 20 attendees?','student_club','MEDIUM','SELECT a.link_to_event AS event_id, COUNT(*) AS attendees FROM attendance a GROUP BY a.link_to_event HAVING COUNT(*) > 20 ORDER BY attendees DESC;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(12,'How many events have above-average attendance?','student_club','HARD','WITH per_event AS (SELECT link_to_event, COUNT(*) AS attendees FROM attendance GROUP BY link_to_event)\nSELECT COUNT(*) AS events_above_avg FROM per_event WHERE attendees > (SELECT AVG(attendees) FROM per_event);',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(13,'How many events have above-average total spending (based on money spent)?','student_club','HARD','SELECT COUNT(*) AS events_above_avg_spending\nFROM (SELECT b.link_to_event, SUM(b.spent) AS total_spent FROM budget b GROUP BY b.link_to_event) x\nWHERE x.total_spent > (SELECT AVG(total_spent) FROM (SELECT b.link_to_event, SUM(b.spent) AS total_spent FROM budget b GROUP BY b.link_to_event) y);',0,'Logical error: used amount (quantity) instead of spent (money). SQL executed\nbut answer was incorrect for the question.','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(14,'How many members have attended at least one event that had above-average attendance?','student_club','HARD','SELECT COUNT(DISTINCT a.link_to_member) AS members_in_popular_events\nFROM attendance a\nWHERE a.link_to_event IN (SELECT link_to_event FROM attendance GROUP BY link_to_event HAVING COUNT(*) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM attendance GROUP BY link_to_event) x));',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(15,'For each year, which event had the highest attendance, and how many attendees did it have?','student_club','HARD','SELECT t.yr, t.event_id, t.attendees\nFROM (SELECT YEAR(e.event_date) AS yr, a.link_to_event AS event_id, COUNT(*) AS attendees FROM attendance a JOIN event e ON e.event_id = a.link_to_event GROUP BY YEAR(e.event_date), a.link_to_event) t\nWHERE t.attendees = (SELECT MAX(t2.attendees) FROM (SELECT a2.link_to_event AS event_id, COUNT(*) AS attendees FROM attendance a2 JOIN event e2 ON e2.event_id = a2.link_to_event WHERE YEAR(e2.event_date) = t.yr GROUP BY a2.link_to_event) t2)\nORDER BY t.yr, t.event_id;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(16,'Which members have attended more events than the average number of events attended per member?','student_club','HARD','SELECT m.member_id, COUNT(a.link_to_event) AS total_events\nFROM member m JOIN attendance a ON a.link_to_member = m.member_id\nGROUP BY m.member_id\nHAVING COUNT(a.link_to_event) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM attendance GROUP BY link_to_member) x);',0,'Wrong column name used (a.event_id). Correct column in attendance \ntable is link_to_event.','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(17,'How many races are recorded in the Formula 1 dataset?','formula_1','EASY','SELECT COUNT(*) AS total_races FROM races;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(18,'How many drivers are recorded in the Formula 1 dataset?','formula_1','EASY','SELECT COUNT(DISTINCT year) AS total_seasons FROM races;',0,'Column \'season\' does not exist in races table. Correct column name is \'year\'.','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(19,'How many constructors are there in the dataset?','formula_1','EASY','SELECT COUNT(*) AS total_constructors FROM constructors;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(20,'What is the earliest year recorded in the Formula 1 dataset?','formula_1','EASY','SELECT MIN(year) AS earliest_season FROM races;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(21,'How many races were held in the 2010 season?','formula_1','EASY','SELECT COUNT(*) AS races_2010 FROM races WHERE year = 2010;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(22,'Which circuits have hosted the highest number of races?','formula_1','MEDIUM','SELECT c.name, COUNT(*) AS total_races FROM races r JOIN circuits c ON r.circuitId = c.circuitId GROUP BY c.circuitId, c.name\nORDER BY total_races DESC LIMIT 5;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(23,'How many drivers have won at least one race?','formula_1','MEDIUM','SELECT COUNT(DISTINCT driverId) AS drivers_with_wins FROM results\nWHERE position = 1;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(24,'What is the highest number of races held in a single season?','formula_1','MEDIUM','SELECT MAX(race_count) AS max_races_in_season FROM (SELECT year, COUNT(*) AS race_count FROM races GROUP BY year) x\n;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(25,'How many drivers have achieved at least one podium finish (position â‰¤ 3)?','formula_1','MEDIUM','SELECT COUNT(*) AS drivers_with_podium FROM drivers d\nWHERE EXISTS (SELECT 1 FROM results r WHERE r.driverId = d.driverId AND r.position <= 3);',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(26,'How many different circuits have hosted races after the year 2010?','formula_1','MEDIUM','SELECT COUNT(DISTINCT r.circuitId) AS circuits_after_2010 FROM races r\nWHERE r.year > 2010;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(27,'How many drivers have at least one race win?','formula_1','HARD','SELECT COUNT(DISTINCT driverId) AS drivers_with_wins FROM results\nWHERE position = 1;',0,'Logical error: used podium condition (position <= 3) instead of wins (position = 1).','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(28,'How many races were held in each country?','formula_1