 transactions_1k GROUP BY ProductID) x);',0,'Logical error: used SUM(Amount) (quantity) instead of SUM(Amount * Price) (revenue).','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(41,'Which customers have made transactions above the average transaction amount?','financial','MEDIUM','SELECT CustomerID, COUNT(*) AS high_value_transactions FROM transactions_1k\nWHERE (Amount * Price) > (SELECT AVG(Amount * Price) FROM transactions_1k) GROUP BY CustomerID;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(42,'How many customers have at least one transaction whose value equals their maximum transaction value?','financial','HARD','SELECT COUNT(DISTINCT t.CustomerID) AS customers_with_peak_txn FROM transactions_1k t\nWHERE (t.Amount * t.Price) = (SELECT MAX(t2.Amount * t2.Price) FROM transactions_1k t2 WHERE t2.CustomerID = t.CustomerID);',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(43,'How many products have total revenue above the average product revenue?','financial','HARD','SELECT COUNT(*) AS products_above_avg FROM (\nSELECT p.ProductID, SUM(t.Amount * t.Price) AS total_revenue FROM transactions_1k t JOIN products p ON t.ProductID = p.ProductID GROUP BY p.ProductID\nHAVING SUM(t.Amount * t.Price) > (SELECT AVG(r) FROM (SELECT SUM(Amount * Price) AS r FROM transactions_1k GROUP BY ProductID) x)) q;',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(44,'How many gas stations have at least one transaction value higher than that gas stationâ€™s average transaction value','financial','HARD','SELECT COUNT(DISTINCT t.GasStationID) AS gasstations_with_high_txn\nFROM transactions_1k t JOIN gasstations g ON t.GasStationID = g.GasStationID\nWHERE (t.Amount * t.Price) > (SELECT AVG(t2.Amount * t2.Price) FROM transactions_1k t2 WHERE t2.GasStationID = t.GasStationID);',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(45,'How many customers have never bought ProductID = 1?','financial','HARD','SELECT COUNT(DISTINCT t.CustomerID) AS customers_never_