superhero s\nWHERE NOT EXISTS (\n  SELECT 1 FROM hero_power hp WHERE hp.hero_id = s.id\n);',1,'','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(58,'How many heroes have the most common eye colour?','superhero','HARD','SELECT COUNT(*) AS heroes_most_common_eye_colour\nFROM superhero s\nWHERE s.eye_colour_id = (\n  SELECT eye_colour_id FROM superhero GROUP BY eye_colour_id ORDER BY COUNT(*) DESC LIMIT 1\n);',0,'Wrong FK column (eye_id). Also subquery must be based on superhero frequency, not colour table alone.','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(59,'How many superheroes have more powers than the average superhero?','superhero','HARD','SELECT COUNT(*) AS heroes_above_avg_powers\nFROM (SELECT hero_id, COUNT(*) AS power_count FROM hero_power GROUP BY hero_id HAVING COUNT(*) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM hero_power GROUP BY hero_id) x)) y;',0,'Logical error: compared hero ids instead of power counts. Corrected to count powers per hero and compare to average.','2026-03-01 19:58:26','2026-03-01 19:58:26',NULL),(60,'How many superheroes have the maximum number of powers assigned to any hero?','superhero','HARD','SELECT COUNT(*) AS heroes_with_max_powers FROM (SELECT hero_id, COUNT(*) AS power_count FROM hero_power GROUP BY hero_id HAVING COUNT(*) = (SELECT MAX(cnt) FROM (SELECT COUNT(*) AS cnt FROM hero_power GROUP BY hero_id) x)) y;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(61,'How many cards exist in the database?','card_games','EASY','SELECT COUNT(*) AS total_cards FROM cards;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(62,'How many distinct suits are there?','card_games','EASY','SELECT COUNT(DISTINCT type) AS distinct_card_types FROM card;',0,'Unknown column error: suit does not exist in card table. Correct column name is type.','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(63,'How many cards were issued after January 1, 1995?','card_games','EASY','SELECT COUNT(*) AS cards_after_1995 FROM card WHERE issued > \'1995-01-01\';',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(64,'What is the most recent card issue date?','card_games','EASY','SELECT MAX(issued) AS latest_issue_date FROM card;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(65,'How many cards are of type \'gold\'?','card_games','EASY','SELECT COUNT(*) AS gold_cards FROM card WHERE type = \'gold\';',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(66,'How many clients have more than one card?','card_games','MEDIUM','SELECT COUNT(*) AS clients_with_multiple_cards FROM (SELECT d.client_id FROM disp d JOIN card c ON c.disp_id = d.disp_id GROUP BY d.client_id HAVING COUNT(*) > 1) x;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(67,'Which 5 clients have the earliest card issue date?','card_games','MEDIUM','SELECT d.client_id, MIN(c.issued) AS first_card_date FROM disp d JOIN card c ON c.disp_id = d.disp_id GROUP BY d.client_id ORDER BY first_card_date ASC LIMIT 5;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(68,'How many accounts have more than 5 cards?','card_games','MEDIUM','SELECT COUNT(*) AS accounts_with_many_cards FROM (SELECT d.account_id FROM disp d JOIN card c ON c.disp_id = d.disp_id GROUP BY d.account_id HAVING COUNT(*) > 5) x;',0,'Incorrect join: card does not link directly to account. Must join via disp table.','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(69,'Which 5 accounts have the most cards?','card_games','MEDIUM','SELECT d.account_id, COUNT(*) AS num_cards FROM disp d GROUP BY d.account_id ORDER BY num_cards DESC LIMIT 5;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(70,'Which clients have cards linked to more than 1 account?','card_games','MEDIUM','SELECT d.client_id FROM disp d GROUP BY d.client_id HAVING COUNT(DISTINCT d.account_id) > 1;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(71,'Which 5 clients have the highest total number of cards across all their accounts?','card_games','HARD','WITH cc AS (SELECT d.client_id, COUNT(*) AS cards_cnt FROM disp d JOIN card c ON c.disp_id=d.disp_id GROUP BY d.client_id) SELECT client_id, cards_cnt FROM cc ORDER BY cards_cnt DESC LIMIT 5;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(72,'For each card type, what percentage of cards were issued after 1998-01-01?','card_games','HARD','WITH x AS (SELECT type, SUM(CASE WHEN issued>\'1998-01-01\' THEN 1 ELSE 0 END) AS after_cnt, COUNT(*) AS total_cnt FROM card GROUP BY type) SELECT type, ROUND(100*after_cnt/total_cnt,2) AS pct_after_1998 FROM x ORDER BY pct_after_1998 DESC;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(73,'Which accounts have more than 2 different card types?','card_games','HARD','SELECT d.account_id, COUNT(DISTINCT c.type) AS distinct_types FROM disp d JOIN card c ON c.disp_id = d.disp_id GROUP BY d.account_id ORDER BY distinct_types DESC LIMIT 10;',0,'used c.account_id in the join, but the card table does not have account_id. Fix: The correct relationship is via disp_id: card.disp_id = disp.disp_id, and account_id comes from disp.','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(74,'Which accounts have total transactions over 1,000,000 and at least 20 transactions?','card_games','HARD','SELECT t.account_id, COUNT(*) AS tx_cnt, SUM(t.amount) AS total_amount FROM trans t GROUP BY t.account_id HAVING SUM(t.amount)>1000000 AND COUNT(*)>=20;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(75,'Which districts have more than 10 clients and what is their average age?','card_games','HARD','SELECT d.district_id, COUNT(*) AS num_clients, ROUND(AVG(TIMESTAMPDIFF(YEAR,c.birth_date,CURDATE())),1) AS avg_age FROM client c JOIN district d ON d.district_id=c.district_id GROUP BY d.district_id HAVING COUNT(*)>10;',0,'Mistake: joined using d.A1, but the district table does not contain column A1. Fix: The correct join is district.district_id = client.district_id.','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(76,'Which clients have a total transaction amount greater than the average total transaction amount per client?','card_games','HARD','SELECT x.client_id, x.total_amount FROM (SELECT d.client_id, SUM(t.amount) AS total_amount FROM disp d JOIN trans t ON d.account_id=t.account_id GROUP BY d.client_id) x WHERE x.total_amount > (SELECT AVG(total_per_client) FROM (SELECT SUM(t.amount) AS total_per_client FROM disp d JOIN trans t ON d.account_id=t.account_id GROUP BY d.client_id) y);',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(77,'Which accounts have more outgoing than incoming transactions and at least 30 transactions in total?','card_games','HARD','SELECT t.account_id FROM trans t GROUP BY t.account_id HAVING SUM(CASE WHEN t.type=\'VYDAJ\' THEN 1 ELSE 0 END) > SUM(CASE WHEN t.type=\'PRIJEM\' THEN 1 ELSE 0 END) AND COUNT(*)>=30;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(78,'How many schools are there?','california_schools','EASY','SELECT COUNT(*) FROM schools;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(79,'How many schools are in each county?','california_schools','EASY','SELECT county, COUNT(*) FROM schools GROUP BY county;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(80,'Which 5 schools have the highest total SAT score?','california_schools','EASY','SELECT sname, (AvgScrRead+AvgScrMath+AvgScrWrite) AS total_sat FROM satscores ORDER BY total_sat DESC LIMIT 5;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(81,'How many schools have at least 50 students scoring 1500+?','california_schools','EASY','SELECT COUNT(*) FROM satscores WHERE NumGE1500 >= 50;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(82,'What is the maximum SAT Math score?','california_schools','EASY','SELECT MAX(AvgScrMath) FROM satscores;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(83,'Which schools have an average SAT score above 1200?','california_schools','EASY','SELECT sname FROM satscores WHERE (AvgScrRead+AvgScrMath+AvgScrWrite) > 1200;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(84,'Which counties have at least 3 schools with more than 100 test takers?','california_schools','MEDIUM','SELECT sc.County FROM schools sc JOIN satscores ss ON sc.CDSCode = ss.cds WHERE ss.NumTstTakr > 100 GROUP BY sc.County HAVING COUNT(*) >= 3;',0,'Mistake: used sc.cds and sc.county, but schools has CDSCode and County. Fix: join with sc.CDSCode = ss.cds and group by sc.County.','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(85,'Which school types (rtype) have an average total SAT above 1200?','california_schools','MEDIUM','SELECT rtype, AVG(AvgScrRead+AvgScrMath+AvgScrWrite) AS avg_total FROM satscores GROUP BY rtype HAVING avg_total > 1200;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(86,'Which counties have a maximum Reading SAT score above 550?','california_schools','MEDIUM','SELECT sc.County, MAX(ss.AvgScrRead) AS max_read FROM schools sc JOIN satscores ss ON sc.CDSCode = ss.cds GROUP BY sc.County HAVING max_read > 550;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(87,'Which counties have an average Reading score higher than the overall Reading average?','california_schools','MEDIUM','SELECT sc.County FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds GROUP BY sc.County HAVING AVG(ss.AvgScrRead)>(SELECT AVG(AvgScrRead) FROM satscores);',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(88,'Which counties have at least 5 schools where Math score is greater than Reading score?','california_schools','MEDIUM','SELECT sc.County FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds WHERE ss.AvgScrMath>ss.AvgScrRead GROUP BY sc.County HAVING COUNT(*)>=5;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(89,'Which counties have an average total SAT score above the statewide average AND at least 10 schools with SAT data?','california_schools','HARD','SELECT sc.County FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds GROUP BY sc.County HAVING AVG(ss.AvgScrRead+ss.AvgScrMath+ss.AvgScrWrite)>(SELECT AVG(AvgScrRead+AvgScrMath+AvgScrWrite) FROM satscores) AND COUNT(*)>=10;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(90,'Which counties have the highest average total SAT score? (Top 5)','california_schools','HARD','SELECT sc.County, AVG(ss.AvgScrRead+ss.AvgScrMath+ss.AvgScrWrite) AS avg_total FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds GROUP BY sc.County ORDER BY avg_total DESC LIMIT 5;',0,'Mistake: Missing GROUP BY sc.County. Aggregate AVG() is used without grouping, so the query is invalid/wrong for \'  per county\' \'.','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(91,'Which counties have more than 5 schools scoring above the statewide average total SAT?','california_schools','HARD','SELECT sc.County FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds WHERE (ss.AvgScrRead+ss.AvgScrMath+ss.AvgScrWrite)>(SELECT AVG(AvgScrRead+AvgScrMath+AvgScrWrite) FROM satscores) GROUP BY sc.County HAVING COUNT(*)>5;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(92,'Which counties have an average total SAT score at least 50 points higher than the statewide average AND at least 15 schools?','california_schools','HARD','SELECT sc.County FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds GROUP BY sc.County HAVING AVG(ss.AvgScrRead+ss.AvgScrMath+ss.AvgScrWrite) >= (SELECT AVG(AvgScrRead+AvgScrMath+AvgScrWrite)+50 FROM satscores) AND COUNT(*)>=15;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(93,'Which schools rank in the top 3 total SAT scores within their county?','california_schools','HARD','SELECT sc.County, ss.sname, (ss.AvgScrRead+ss.AvgScrMath+ss.AvgScrWrite) AS total_sat FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds WHERE (SELECT COUNT(*) FROM schools sc2 JOIN satscores ss2 ON sc2.CDSCode=ss2.cds WHERE sc2.County=sc.County AND (ss2.AvgScrRead+ss2.AvgScrMath+ss2.AvgScrWrite)>(ss.AvgScrRead+ss.AvgScrMath+ss.AvgScrWrite))<3;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(94,'How many molecules are recorded in the dataset?','toxicology','EASY','SELECT COUNT(*) AS total_molecules FROM molecule;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(95,'How many molecules contain more than 10 atoms?','toxicology','MEDIUM','SELECT COUNT(*) FROM (SELECT m.molecule_id FROM molecule m JOIN atom a ON a.molecule_id = m.molecule_id GROUP BY m.molecule_id HAVING COUNT(a.atom_id) > 10) x;',0,'Incorrect column reference: atom_count does not exist. Must count atoms via JOIN and GROUP BY.','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(96,'How many molecules have more atoms than the average molecule?','toxicology','HARD','SELECT COUNT(*) FROM (SELECT molecule_id, COUNT(*) AS atom_count FROM atom GROUP BY molecule_id HAVING COUNT(*) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM atom GROUP BY molecule_id) t)) x;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(97,'How many molecules have bonds above the average number of bonds per molecule?','toxicology','HARD','SELECT COUNT(*) FROM (SELECT molecule_id, COUNT(*) AS bond_cnt FROM bond GROUP BY molecule_id HAVING COUNT(*) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM bond GROUP BY molecule_id) x)) t;',1,'','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(98,'Which molecule has the maximum number of bonds?','toxicology','HARD','SELECT molecule_id, COUNT(*) AS bond_cnt FROM bond GROUP BY molecule_id ORDER BY bond_cnt DESC LIMIT 1;',0,'Invalid nested aggregation: MAX(COUNT(*)) is not allowed. Use ORDER BY + LIMIT or a subquery.','2026-03-01 22:20:06','2026-03-01 22:20:06',NULL),(99,'How many transactions does each account have? (Top 10)','debit_card_specializing','MEDIUM','SELECT account_id, COUNT(*) AS txn_count FROM trans GROUP BY account_id ORDER BY txn_count DESC LIMIT 10;',1,'','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(100,'How many accounts have more than 5 loans?','debit_card_specializing','MEDIUM','SELECT COUNT(*) FROM (SELECT account_id FROM loan GROUP BY account_id HAVING COUNT(*) > 5) x;',0,'Column loan_count does not exist. Must count loans via JOIN and GROUP BY.','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(101,'How many accounts have more transactions than the average account?','debit_card_specializing','HARD','SELECT COUNT(*) FROM (SELECT account_id, COUNT(*) AS cnt FROM trans GROUP BY account_id HAVING COUNT(*) > (SELECT AVG(c) FROM (SELECT COUNT(*) AS c FROM trans GROUP BY account_id) x)) t;',1,'','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(102,'Which account has the maximum balance recorded in transactions?','debit_card_specializing','HARD','SELECT account_id, SUM(balance) AS total_balance FROM trans GROUP BY account_id ORDER BY total_balance DESC LIMIT 1;',0,'Invalid nested aggregation: MAX(SUM(balance)) not allowed. Use ORDER BY SUM(balance) DESC LIMIT 1.','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(103,'How many posts are recorded?','codebase_community','EASY','SELECT COUNT(*) AS total_users FROM users;',1,'','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(104,'How many users have more than 5 posts?','codebase_community','MEDIUM','SELECT COUNT(*) FROM (SELECT OwnerUserId FROM posts GROUP BY OwnerUserId HAVING COUNT(*) > 5) x;',0,'Column post_count does not exist in users table. Must count posts via GROUP BY on posts table.','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(105,'Which 10 users have written the most posts?','codebase_community','MEDIUM','SELECT OwnerUserId, COUNT(*) AS post_count FROM posts GROUP BY OwnerUserId ORDER BY post_count DESC LIMIT 10;',1,'','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(106,'How many users have more posts than the average user?','codebase_community','HARD','SELECT COUNT(*) FROM (SELECT OwnerUserId, COUNT(*) AS cnt FROM posts GROUP BY OwnerUserId HAVING COUNT(*) > (SELECT AVG(c) FROM (SELECT COUNT(*) AS c FROM posts GROUP BY OwnerUserId) x)) t;',1,'','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(107,'Which user has the highest total votes received on their posts?','codebase_community','HARD','SELECT p.OwnerUserId, COUNT(*) AS vote_count FROM posts p JOIN votes v ON v.PostId = p.Id GROUP BY p.OwnerUserId ORDER BY vote_count DESC LIMIT 1;',0,'Invalid nested aggregation and wrong logic. Votes must be joined with posts to attribute votes to post owners.','2026-03-01 22:27:49','2026-03-01 22:27:49',NULL),(108,'How many patients are recorded?','thrombosis_prediction','EASY','SELECT COUNT(*) AS total_patients FROM patient;',1,'','2026-03-01 22:27:49','2026-03-03 14:02:55',NULL),(112,'Which matches ended in a draw, and what were The participating teams and their scores?','Customed (match, team)','EASY','SELECT m.match_api_id, t1.team_long_name AS home_team, t2.team_long_name AS away_team, m.home_team_goal, m.away_team_goal FROM `match` m JOIN team t1 ON m.home_team_api_id = t1.team_api_id JOIN team t2 ON m.away_team_api_id = t2.team_api_id WHERE m.home_team_goal = m.away_team_goal ORDER BY m.date DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(113,'Calculate the number of superheroes that belong to Each publisher.','Custom(superhero, publisher)','EASY','SELECT p.publisher_name, COUNT(s.id) AS hero_count FROM publisher p JOIN superhero s ON p.id = s.publisher_id GROUP BY p.publisher_name ORDER BY hero_count DESC;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(114,'Identify the constructors whose drivers accumulated the Highest number of race points.','Custom constructors, results','EASY','SELECT c.name, SUM(r.points) AS total_points FROM constructors c JOIN results r ON c.constructorId = r.constructorId GROUP BY c.name ORDER BY total_points DESC LIMIT 10;',0,'Using COUNT instead of SUM; incorrect table alias','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(115,'Compute the total revenue generated by each gas station based on fuel sales.','Custom(transactions_1k, gasstations)','EASY','SELECT d.forename, d.surname, SUM(r.points) AS total_points FROM drivers d JOIN results r ON d.driverId = r.driverId GROUP BY d.driverId ORDER BY total_points DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(116,'List the drivers who scored points in races and Display their total points.','Custom(drivers, results)','EASY','SELECT d.forename,d.surname,SUM(r.points) AS total_pointsFROM drivers dJOIN results r ON d.driverId = r.driverIdGROUP BY d.driverIdORDER BY total_points DESCLIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(117,'Which drivers have an average race score higher Than the overall average race score across all drivers?','Customed (drivers, results)','EASY','SELECT d.driverRef, AVG(r.points) AS avg_points FROM drivers d JOIN results r ON d.driverId = r.driverId GROUP BY d.driverId HAVING AVG(r.points) > (SELECT AVG(points) FROM results);',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(118,'Display the football teams with the highest average player rating.','Custom(team, match, player, Player_attributes)','EASY','SELECT t.team_long_name, AVG(pa.overall_rating) AS avg_rating FROM team t JOIN `match` m ON t.team_api_id = m.home_team_api_id JOIN player p ON m.home_player_1 = p.player_api_id JOIN player_attributes pa ON p.player_api_id = pa.player_api_id GROUP BY t.team_long_name ORDER BY avg_rating DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(119,'Which users have received more votes on their posts than the average number of votes received by users?','Customed (users, posts, votes)','EASY','SELECT u.Id, COUNT(v.Id) AS votes_received FROM users u JOIN posts p ON u.Id = p.OwnerUserId JOIN votes v ON p.Id = v.PostId GROUP BY u.Id HAVING COUNT(v.Id) > (SELECT AVG(vote_count) FROM (SELECT COUNT(*) vote_count FROM votes GROUP BY UserId) x);',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(120,'Which drivers have won more races than the average number of wins among all drivers, and for which constructors did those wins occur?','Customed (drivers, results, constructors)','EASY','SELECT d.driverRef, c.name AS constructor, COUNT(*) AS wins FROM drivers d JOIN results r ON d.driverId = r.driverId JOIN constructors c ON r.constructorId = c.constructorId WHERE r.position = 1 GROUP BY d.driverId, c.constructorId HAVING COUNT(*) > (SELECT AVG(win_count) FROM (SELECT COUNT(*) AS win_count FROM results WHERE position = 1 GROUP BY driverId) x);',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(121,'Which card sets have the most cards with isFoil=1 and also have highest average convertedManaCost?','Customed (cards, sets, legalities)','EASY','SELECT se.name AS set_name, COUNT(c.id) AS foil_count, AVG(c.convertedManaCost) AS avg_cmc FROM cards c JOIN sets se ON c.setCode = se.code JOIN legalities l ON c.uuid = l.uuid WHERE c.hasFoil = 1 GROUP BY se.name ORDER BY foil_count DESC, avg_cmc DESC LIMIT 10;',0,'Missing DESC LIMIT 10','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(122,'Which gas stations generated the highest total revenue from transactions?','Customed(transactions_1k, gasstations, products)','EASY','SELECT g.GasStationID, COUNT(t.TransactionID) AS total_transactions, SUM(t.Amount * t.Price) AS revenue FROM transactions_1k t JOIN gasstations g ON t.GasStationID = g.GasStationID JOIN products p ON t.ProductID = p.ProductID GROUP BY g.GasStationID ORDER BY revenue DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(123,'Which drivers finished races in the top 3 positions and what constructors did they drive for?','Customed(drivers, results, constructors, races)','MEDIUM','SELECT d.forename, d.surname, c.name AS constructor, r.name AS race, res.position FROM drivers d JOIN results res ON d.driverId = res.driverId JOIN constructors c ON res.constructorId = c.constructorId JOIN races r ON res.raceId = r.raceId WHERE res.position <= 3 ORDER BY r.year DESC;',0,'Wrong JOIN condition','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(124,'Which superheroes have more powers than the average number of powers per superhero and what publisher are they associated with?','Customed (superhero, publisher,hero_power)','MEDIUM','SELECT s.superhero_name, p.publisher_name, COUNT(hp.power_id) AS total_powers FROM superhero s JOIN hero_power hp ON s.id = hp.hero_id JOIN publisher p ON s.publisher_id = p.id GROUP BY s.id, p.id HAVING COUNT(hp.power_id) > (SELECT AVG(power_count) FROM (SELECT COUNT(*) power_count FROM hero_power GROUP BY hero_id) x);',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(125,'Find the clients who performed the highest number of transactions and calculate the total amount they transferred.','Custom (client, disp, account, trans)','MEDIUM','SELECT c.client_id, COUNT(t.trans_id) AS total_transactions, SUM(t.amount) AS total_amount FROM client c JOIN disp d ON c.client_id = d.client_id JOIN account a ON d.account_id = a.account_id JOIN trans t ON a.account_id = t.account_id GROUP BY c.client_id ORDER BY total_transactions DESC LIMIT 10;',0,'Incorrect ORDER BY column; missing JOIN','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(126,'Which clients have accounts with more than 20 transactions and what is their total transaction amount?','Customed(client, disp, account, trans)','MEDIUM','SELECT c.client_id, COUNT(t.trans_id) AS transaction_count, SUM(t.amount) AS total_amount FROM client c JOIN disp d ON c.client_id = d.client_id JOIN account a ON d.account_id = a.account_id JOIN trans t ON a.account_id = t.account_id GROUP BY c.client_id HAVING COUNT(t.trans_id) > 20;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(127,'Which gas stations have customers with the highest cumulative transactions and repeated visits?','Customed(transactions_1k, customers, gasstations, Yearmonth)','MEDIUM','SELECT g.GasStationID, g.ChainID, COUNT(DISTINCT t.CustomerID) AS unique_customers, SUM(t.Amount) AS total_spent, COUNT(t.TransactionID) AS total_visits FROM transactions_1k t JOIN gasstations g ON t.GasStationID = g.GasStationID JOIN customers c ON t.CustomerID = c.CustomerID JOIN yearmonth y ON y.CustomerID = c.CustomerID GROUP BY g.GasStationID, g.ChainID ORDER BY total_spent DESC, total_visits DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(128,'Which football teams played matches where the total Goals scored were higher than the league average?','Customed(match, team, league, country)','MEDIUM','WITH avg_goals AS (SELECT AVG(home_team_goal + away_team_goal) AS avg_goal FROM `match`) SELECT t.team_long_name, COUNT(m.match_api_id) AS high_scoring_matches FROM `match` m JOIN team t ON m.home_team_api_id = t.team_api_id JOIN league l ON m.league_id = l.id JOIN country c ON l.country_id = c.id JOIN avg_goals ag WHERE (m.home_team_goal + m.away_team_goal) > ag.avg_goal GROUP BY t.team_long_name ORDER BY high_scoring_matches DESC;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(129,'Which publishers have a \"Power Monopoly\"\"? Find publishers who own more than 40% of all superheroes that possess a specific \"\"God-tier\"\" power (powers held by fewer than 10 heroes in total).\"','Customed (superhero, publisher, hero_power, superpower)','MEDIUM','SELECT p.publisher_name, sp2.power_name, COUNT(s.id) AS hero_count, (COUNT(s.id) * 100.0 / (SELECT COUNT(*) FROM hero_power hp2 WHERE hp2.power_id = hp.power_id)) AS market_share FROM publisher p JOIN superhero s ON p.id = s.publisher_id JOIN hero_power hp ON s.id = hp.hero_id JOIN superpower sp2 ON hp.power_id = sp2.id WHERE hp.power_id IN (SELECT power_id FROM hero_power GROUP BY power_id HAVING COUNT(hero_id) < 10) GROUP BY p.id, p.publisher_name, sp2.power_name, hp.power_id HAVING market_share > 40 ORDER BY market_share DESC;',0,'Wrong JOIN condition; missing HAVING','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(130,'Which publishers own \"rare\"\" superheroesâ€”defined as characters who possess a superpower that fewer than 5% of all superheroes in the database have?\"','Customed (superhero, publisher, hero_power, superpower)','MEDIUM','SELECT p.publisher_name, s.superhero_name, sp2.power_name FROM superhero s JOIN publisher p ON s.publisher_id = p.id JOIN hero_power hp ON s.id = hp.hero_id JOIN superpower sp2 ON hp.power_id = sp2.id WHERE hp.power_id IN (SELECT power_id FROM hero_power GROUP BY power_id HAVING COUNT(hero_id) < (SELECT COUNT(*) FROM superhero) * 0.05) ORDER BY p.publisher_name ASC;',0,'Incorrect table alias','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(131,'Determine the districts with the largest transactionVolume and number of clients.','Custom (district, client, disp, account, trans)','MEDIUM','SELECT d.district_id, COUNT(DISTINCT c.client_id) AS clients, SUM(t.amount) AS transaction_volume FROM district d JOIN client c ON d.district_id = c.district_id JOIN disp di ON c.client_id = di.client_id JOIN account a ON di.account_id = a.account_id JOIN trans t ON a.account_id = t.account_id GROUP BY d.district_id ORDER BY transaction_volume DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(132,'Which publishers have the most diverse superheroes in terms of their moral alignment, gender representation, and the total variety of unique superpowers they possess? Rank them by the count of unique powers.','Customed (superhero, publisher, alignment, Gender, hero_power)','MEDIUM','SELECT p.publisher_name, COUNT(DISTINCT s.alignment_id) AS distinct_alignments, COUNT(DISTINCT s.gender_id) AS distinct_genders, COUNT(DISTINCT hp.power_id) AS unique_powers_count, COUNT(s.id) AS total_superheroes FROM publisher p JOIN superhero s ON p.id = s.publisher_id JOIN hero_power hp ON s.id = hp.hero_id GROUP BY p.id, p.publisher_name ORDER BY unique_powers_count DESC, distinct_alignments DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(133,'Which superheroes have more powers than the average number of powers per superhero and what publisher are they associated with?','Customed (superhero, publisher,hero_power)','MEDIUM','SELECT s.superhero_name, p.publisher_name, COUNT(hp.power_id) AS total_powers FROM superhero s JOIN hero_power hp ON s.id = hp.hero_id JOIN publisher p ON s.publisher_id = p.id GROUP BY s.id, p.id HAVING COUNT(hp.power_id) > (SELECT AVG(power_count) FROM (SELECT COUNT(*) power_count FROM hero_power GROUP BY hero_id) x);',0,'Column does not exist; typo in table name','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(134,'Which districts have a total sum of transactions greater than the average total transaction amount per account across the entire database, and what are the number of distinct clients, total transaction amount, and average loan amount for those districts?','Customed (district, client, disp, account, trans, loan)','HARD','SELECT d.district_id, COUNT(DISTINCT c.client_id) AS clients, SUM(t.amount) AS total_transactions, AVG(l.amount) AS avg_loan FROM district d JOIN client c ON d.district_id = c.district_id JOIN disp di ON c.client_id = di.client_id JOIN account a ON di.account_id = a.account_id JOIN trans t ON a.account_id = t.account_id LEFT JOIN loan l ON a.account_id = l.account_id GROUP BY d.district_id HAVING total_transactions > (SELECT AVG(total_sum) FROM (SELECT SUM(amount) total_sum FROM trans GROUP BY account_id) t);',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(135,'Which districts have clients with the highest average Account balance and also have active loans?','Customed(district, client, disp, account, trans, loan)','HARD','WITH account_balance AS (SELECT account_id, MAX(balance) AS latest_balance FROM trans GROUP BY account_id) SELECT d.district_id, AVG(ab.latest_balance) AS avg_balance, COUNT(DISTINCT l.loan_id) AS loan_count FROM district d JOIN client c ON d.district_id = c.district_id JOIN disp di ON c.client_id = di.client_id JOIN account a ON di.account_id = a.account_id JOIN account_balance ab ON a.account_id = ab.account_id LEFT JOIN loan l ON a.account_id = l.account_id GROUP BY d.district_id ORDER BY avg_balance DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(136,'Which football teams have the most dominant performance considering wins, goals, player ratings, and team Tactical attributes?','Custom(match, team, player, player_attributes, Team_attributes, league, country)','HARD','SELECT t.team_long_name, COUNT(m.match_api_id) AS matches, SUM(CASE WHEN m.home_team_goal > m.away_team_goal THEN 1 ELSE 0 END) AS wins, AVG(pa.overall_rating) AS avg_player_rating, AVG(ta.buildUpPlaySpeed) AS avg_speed, AVG(ta.chanceCreationShooting) AS avg_attack FROM `match` m JOIN team t ON m.home_team_api_id = t.team_api_id JOIN league l ON m.league_id = l.id JOIN country c ON l.country_id = c.id JOIN team_attributes ta ON t.team_api_id = ta.team_api_id JOIN player p ON m.home_player_1 = p.player_api_id JOIN player_attributes pa ON p.player_api_id = pa.player_api_id GROUP BY t.team_long_name ORDER BY wins DESC, avg_player_rating DESC LIMIT 10;',0,'Using INNER JOIN instead of  JOIN;','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(137,'Find the top 5 drivers who recorded the fastest laps inraces but whose constructors scored the least total points.','Customed(drivers, driverstandings, results, constructorstandings, constructors, races,laptimes)','HARD','SELECT d.forename, d.surname, r.name AS race_name, l.milliseconds AS fastest_lap_time, cs.points AS constructor_points, c.name AS constructor_name FROM drivers d JOIN results res ON d.driverId = res.driverId JOIN races r ON res.raceId = r.raceId JOIN laptimes l ON d.driverId = l.driverId AND r.raceId = l.raceId JOIN constructorstandings cs ON res.constructorId = cs.constructorId AND r.raceId = cs.raceId JOIN constructors c ON cs.constructorId = c.constructorId WHERE l.position = 1 ORDER BY cs.points ASC, l.milliseconds ASC LIMIT 5;',0,'Incorrect subquery returning multiple rows','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(138,'Which districts generate the highest financial activity considering number of clients, accounts, transactions, Loans, cards, and average balances?','Custom (district, client, disp, account, trans, loan, card)','HARD','WITH balance_table AS (SELECT account_id, MAX(balance) AS last_balance FROM trans GROUP BY account_id) SELECT d.district_id, COUNT(DISTINCT c.client_id) AS total_clients, COUNT(DISTINCT a.account_id) AS accounts, COUNT(DISTINCT ca.card_id) AS cards, COUNT(DISTINCT l.loan_id) AS loans, SUM(t.amount) AS transaction_volume, AVG(bt.last_balance) AS avg_balance FROM district d JOIN client c ON d.district_id = c.district_id JOIN disp di ON c.client_id = di.client_id JOIN account a ON di.account_id = a.account_id JOIN trans t ON a.account_id = t.account_id LEFT JOIN loan l ON a.account_id = l.account_id LEFT JOIN card ca ON di.disp_id = ca.disp_id LEFT JOIN balance_table bt ON a.account_id = bt.account_id GROUP BY d.district_id ORDER BY transaction_volume DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(139,'Which districts have the highest financial activity including number of clients, total transactions, loans, and average transaction value?','Customed(district, client, disp, account, trans, loan, card)','HARD','SELECT d.district_id, COUNT(DISTINCT c.client_id) AS clients, COUNT(DISTINCT a.account_id) AS accounts, COUNT(t.trans_id) AS transactions, SUM(t.amount) AS total_volume, AVG(t.amount) AS avg_transaction, COUNT(DISTINCT l.loan_id) AS loans, COUNT(DISTINCT ca.card_id) AS cards FROM district d JOIN client c ON d.district_id = c.district_id JOIN disp di ON c.client_id = di.client_id JOIN account a ON di.account_id = a.account_id JOIN trans t ON a.account_id = t.account_id LEFT JOIN loan l ON a.account_id = l.account_id LEFT JOIN card ca ON di.disp_id = ca.disp_id GROUP BY d.district_id ORDER BY total_volume DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(140,'Which Formula 1 drivers demonstrate the best race performance considering race results, fastest laps, pit stops, constructor standings, and championship points?','Custom (drivers, results, races, constructors, Driverstandings, constructorstandings, Laptimes, pitstops)','HARD','WITH driver_stats AS (SELECT d.driverId, AVG(res.position) AS avg_finish, MIN(l.milliseconds) AS best_lap, AVG(ps.milliseconds) AS avg_pitstop, SUM(res.points) AS race_points FROM drivers d JOIN results res ON d.driverId = res.driverId JOIN races r ON res.raceId = r.raceId JOIN laptimes l ON d.driverId = l.driverId AND r.raceId = l.raceId JOIN pitstops ps ON d.driverId = ps.driverId AND r.raceId = ps.raceId GROUP BY d.driverId) SELECT d.forename, d.surname, ds.avg_finish, ds.best_lap, ds.avg_pitstop, ds.race_points, SUM(cs.points) AS constructor_points FROM driver_stats ds JOIN drivers d ON ds.driverId = d.driverId JOIN results res ON d.driverId = res.driverId JOIN constructors c ON res.constructorId = c.constructorId JOIN constructorstandings cs ON c.constructorId = cs.constructorId GROUP BY d.driverId ORDER BY ds.race_points DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(141,'Which publishers produce superheroes with the most diverse powers, attributes, alignments, And physical characteristics?','Custom (superhero, hero_power, superpower, superhero_attribute, attribute, publisher, alignment, gender, colour)','HARD','SELECT p.publisher_name, COUNT(DISTINCT s.id) AS heroes, COUNT(DISTINCT hp.power_id) AS powers, COUNT(DISTINCT sa.attribute_id) AS attributes, COUNT(DISTINCT s.alignment_id) AS alignments, COUNT(DISTINCT s.gender_id) AS genders FROM superhero s JOIN hero_power hp ON s.id = hp.hero_id JOIN superpower sp ON hp.power_id = sp.id JOIN hero_attribute sa ON s.id = sa.hero_id JOIN attribute a ON sa.attribute_id = a.id JOIN publisher p ON s.publisher_id = p.id JOIN alignment al ON s.alignment_id = al.id JOIN gender g ON s.gender_id = g.id LEFT JOIN colour ec ON s.eye_colour_id = ec.id LEFT JOIN colour hc ON s.hair_colour_id = hc.id LEFT JOIN colour sc ON s.skin_colour_id = sc.id GROUP BY p.publisher_name ORDER BY powers DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(142,'Which schools demonstrate the strongest academic outcomes considering SAT scores, enrollment, And free meal eligibility?','Custom (schools, frpm, satscores)','HARD','WITH academic_score AS (SELECT cds, AVG(AvgScrMath + AvgScrRead + AvgScrWrite) AS total_sat FROM satscores GROUP BY cds) SELECT s.School, s.District, a.total_sat, AVG(f.`Percent (%) Eligible FRPM (K-12)`) AS poverty_rate, AVG(f.`Enrollment (K-12)`) AS enrollment FROM schools s JOIN frpm f ON s.CDSCode = f.CDSCode JOIN academic_score a ON s.CDSCode = a.cds GROUP BY s.School, s.District, a.total_sat ORDER BY total_sat DESC LIMIT 10;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(143,'Find the top 5 drivers who consistently perform above average by comparing their average finish position with the global average, while also considering their fastest lap and total points.','Custom (drivers, results, races,laptimes,constructors)','HARD','WITH driver_performance AS (SELECT d.driverId, AVG(res.position) AS avg_finish, MIN(l.milliseconds) AS fastest_lap, SUM(res.points) AS total_points FROM drivers d JOIN results res ON d.driverId = res.driverId JOIN races r ON res.raceId = r.raceId JOIN laptimes l ON d.driverId = l.driverId AND r.raceId = l.raceId JOIN constructors c ON res.constructorId = c.constructorId GROUP BY d.driverId), global_avg AS (SELECT AVG(position) AS avg_position FROM results) SELECT d.forename, d.surname, dp.avg_finish, dp.fastest_lap, dp.total_points FROM driver_performance dp JOIN drivers d ON dp.driverId = d.driverId JOIN global_avg g WHERE dp.avg_finish < g.avg_position ORDER BY dp.total_points DESC, dp.fastest_lap ASC LIMIT 5;',1,'','2026-03-11 20:27:09','2026-03-11 20:27:09',NULL),(146,'test1','bird_app','EASY','test1',1,'test','2026-03-19 10:19:33','2026-03-19 10:19:33','CREATE TABLE test');
